"use client"

import { useState, useEffect } from "react"
import { useParams, useNavigate } from "react-router-dom"
import axios from "axios"
import { API } from "../App"
import { Button } from "../components/ui/button"
import { toast } from "sonner"
import { ArrowLeft, Star, Clock, MapPin, Plus, Minus, ShoppingCart } from "lucide-react"

const RestaurantPage = ({ user }) => {
  const { restaurantId } = useParams()
  const navigate = useNavigate()
  const [restaurant, setRestaurant] = useState(null)
  const [menuItems, setMenuItems] = useState([])
  const [cart, setCart] = useState({})
  const [loading, setLoading] = useState(true)

  const fetchRestaurantData = async () => {
    try {
      console.log("[v0] Starting to fetch restaurant data...")
      console.log("[v0] Restaurant endpoint:", `${API}/restaurants/${restaurantId}`)
      console.log("[v0] Menu endpoint:", `${API}/restaurants/${restaurantId}/menu`)

      // Fetch restaurant details
      const restaurantResponse = await axios.get(`${API}/restaurants/${restaurantId}`)
      console.log("[v0] Restaurant response status:", restaurantResponse.status)
      console.log("[v0] Restaurant data received:", restaurantResponse.data)
      setRestaurant(restaurantResponse.data)

      // Fetch menu items
      const menuResponse = await axios.get(`${API}/restaurants/${restaurantId}/menu`)
      console.log("[v0] Menu response status:", menuResponse.status)
      console.log("[v0] Menu items count:", menuResponse.data.length)
      setMenuItems(menuResponse.data)

      console.log("[v0] Successfully loaded restaurant data")
    } catch (error) {
      console.error("[v0] Error details:")
      console.error("[v0] - Error message:", error.message)
      console.error("[v0] - Response status:", error.response?.status)
      console.error("[v0] - Response data:", error.response?.data)
      console.error("[v0] - Request URL:", error.config?.url)

      if (error.response?.status === 404) {
        toast.error("Restaurant not found")
      } else if (error.response?.status === 500) {
        toast.error("Server error. Please try again later")
      } else if (error.code === "ERR_NETWORK") {
        toast.error("Cannot connect to server. Is the backend running?")
      } else {
        toast.error("Failed to load restaurant")
      }

      setTimeout(() => navigate("/"), 2000)
    } finally {
      setLoading(false)
    }
  }

  const updateCartQuantity = (menuItemId, change) => {
    setCart((prev) => {
      const newQuantity = (prev[menuItemId] || 0) + change
      if (newQuantity <= 0) {
        const { [menuItemId]: _, ...rest } = prev
        return rest
      }
      return { ...prev, [menuItemId]: newQuantity }
    })
  }

  const addToCart = async () => {
    const itemsToAdd = Object.entries(cart)
      .filter(([_, quantity]) => quantity > 0)
      .map(([menuItemId, quantity]) => ({
        menu_item_id: menuItemId,
        quantity,
      }))

    if (itemsToAdd.length === 0) {
      toast.error("Please select items to add to cart")
      return
    }

    try {
      for (const item of itemsToAdd) {
        await axios.post(`${API}/cart/add`, {
          restaurant_id: restaurantId,
          menu_item_id: item.menu_item_id,
          quantity: item.quantity,
        })
      }
      toast.success("Items added to cart!")
      setCart({})
      navigate("/cart")
    } catch (error) {
      console.error("[v0] Error adding to cart:", error)
      toast.error(error.response?.data?.detail || "Failed to add items to cart")
    }
  }

  const getTotalItems = () => {
    return Object.values(cart).reduce((sum, qty) => sum + qty, 0)
  }

  useEffect(() => {
    console.log("[v0] RestaurantPage mounted with ID:", restaurantId)
    console.log("[v0] Full URL params:", restaurantId)
    console.log("[v0] API URL:", API)

    if (restaurantId) {
      fetchRestaurantData()
    } else {
      console.error("[v0] No restaurantId provided in URL params")
      toast.error("Restaurant not found")
      setTimeout(() => navigate("/"), 2000)
    }
  }, [restaurantId])

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <p className="text-lg" data-testid="loading-msg">
          Loading restaurant...
        </p>
      </div>
    )
  }

  if (!restaurant) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <p className="text-lg">Restaurant not found</p>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-[#FFF5EE] to-[#FFE4E1]">
      {/* Header */}
      <div className="bg-white shadow-sm sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 py-4">
          <div className="flex items-center gap-4">
            <Button variant="ghost" onClick={() => navigate("/")} data-testid="back-btn">
              <ArrowLeft className="w-5 h-5" />
            </Button>
            <div className="flex-1">
              <h1 className="text-2xl font-bold text-gray-800">{restaurant.name}</h1>
              <p className="text-sm text-gray-600">{restaurant.cuisine}</p>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 py-8">
        {/* Restaurant Info */}
        <div className="bg-white rounded-2xl shadow-md overflow-hidden mb-8">
          <div className="relative h-64">
            <img
              src={restaurant.image || "/placeholder.svg?height=300&width=1200&query=restaurant+interior"}
              alt={restaurant.name}
              className="w-full h-full object-cover"
            />
          </div>
          <div className="p-6">
            <div className="flex items-center gap-6 text-gray-600">
              <div className="flex items-center gap-2">
                <Star className="w-5 h-5 text-yellow-500 fill-yellow-500" />
                <span className="font-semibold">{restaurant.rating || "4.5"}</span>
              </div>
              <div className="flex items-center gap-2">
                <Clock className="w-5 h-5" />
                <span>{restaurant.delivery_time || "30-40"} min</span>
              </div>
              <div className="flex items-center gap-2">
                <MapPin className="w-5 h-5" />
                <span>{restaurant.location}</span>
              </div>
            </div>
            {restaurant.description && <p className="mt-4 text-gray-700">{restaurant.description}</p>}
          </div>
        </div>

        {/* Menu Items */}
        <div>
          <h2 className="text-2xl font-bold text-gray-800 mb-6">Menu</h2>

          {menuItems.length === 0 ? (
            <div className="bg-white rounded-2xl shadow-md p-12 text-center">
              <p className="text-gray-500 text-lg" data-testid="no-menu-msg">
                No menu items available
              </p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {menuItems.map((item) => (
                <div
                  key={item.id}
                  data-testid={`menu-item-${item.id}`}
                  className="bg-white rounded-2xl shadow-md overflow-hidden hover:shadow-lg transition-shadow"
                >
                  <div className="relative h-48">
                    <img
                      src={item.image || `/placeholder.svg?height=200&width=400&query=${item.name}`}
                      alt={item.name}
                      className="w-full h-full object-cover"
                    />
                    {!item.available && (
                      <div className="absolute inset-0 bg-black/50 flex items-center justify-center">
                        <span className="text-white font-bold">Currently Unavailable</span>
                      </div>
                    )}
                  </div>

                  <div className="p-4">
                    <h3 className="text-lg font-bold text-gray-800 mb-1">{item.name}</h3>
                    <p className="text-sm text-gray-600 mb-3 line-clamp-2">{item.description}</p>

                    <div className="flex items-center justify-between">
                      <span className="text-xl font-bold text-[#FF6B6B]">Rs.{item.price.toFixed(2)}</span>

                      {item.available ? (
                        cart[item.id] > 0 ? (
                          <div className="flex items-center gap-2 bg-[#FF6B6B] text-white rounded-full px-3 py-1">
                            <button
                              onClick={() => updateCartQuantity(item.id, -1)}
                              data-testid={`decrease-qty-${item.id}`}
                              className="hover:opacity-80"
                            >
                              <Minus className="w-4 h-4" />
                            </button>
                            <span className="font-semibold w-6 text-center" data-testid={`qty-${item.id}`}>
                              {cart[item.id]}
                            </span>
                            <button
                              onClick={() => updateCartQuantity(item.id, 1)}
                              data-testid={`increase-qty-${item.id}`}
                              className="hover:opacity-80"
                            >
                              <Plus className="w-4 h-4" />
                            </button>
                          </div>
                        ) : (
                          <Button
                            onClick={() => updateCartQuantity(item.id, 1)}
                            data-testid={`add-btn-${item.id}`}
                            className="bg-[#FF6B6B] hover:bg-[#EE5A52] text-white"
                          >
                            Add
                          </Button>
                        )
                      ) : (
                        <Button disabled variant="secondary">
                          Unavailable
                        </Button>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Floating Cart Button */}
        {getTotalItems() > 0 && (
          <div className="fixed bottom-6 right-6">
            <Button
              onClick={addToCart}
              data-testid="floating-cart-btn"
              className="bg-[#FF6B6B] hover:bg-[#EE5A52] text-white px-8 py-6 rounded-full shadow-lg text-lg"
            >
              <ShoppingCart className="w-5 h-5 mr-2" />
              Add {getTotalItems()} items to Cart
            </Button>
          </div>
        )}
      </div>
    </div>
  )
}

export default RestaurantPage
